parameters.jsCode:
// Валидация запроса от Plane-агента.
// Два режима:
//   NL mode    — body.message: текст, LLM извлекает intent/params
//   Direct mode — body.action: имя операции + body.params: параметры (для тестов без LLM)
//
// Поля в body:
//   message       — NL-запрос (NL mode)
//   action+params — прямой вызов (Direct mode, без LLM)
//   session_id    — для чата (chat_memory)
//   token         — GigaChat-token (planner_sessions, 64 hex), не Plane API
//   workspace_slug — slug Plane workspace (напр. 'office')
//   plane_url     — базовый URL Plane API (напр. 'http://host.docker.internal:8000')
//   plane_token   — Plane API token (X-API-Key)
const body = $input.first().json.body || {};
const message = String(body.message || '').trim();
const session_id = String(body.session_id || 'plane-default').trim();
const directAction = String(body.action || '').trim();

// Health-check
if (message === 'ping') {
  return [{ json: { valid: 0, error: 'pong' } }];
}

const is_direct = directAction.length > 0;
const ALLOWED_ACTIONS = new Set(['list_projects','list_issues','create_issue','update_issue','delete_issue','search_issues','change_status','assign_issue','set_deadline','add_label','remove_label','add_comment','get_issue','bulk','stats','cross_project_search','list_comments','me','list_members','list_cycles','list_modules','list_notifications','list_activity','create_epic','chat']);

if (is_direct) {
  // Direct mode: action обязателен, message — опциональный pseudo-маркер для chat_memory
  if (!ALLOWED_ACTIONS.has(directAction)) {
    return [{ json: { valid: 0, error: 'Неизвестный action: ' + directAction } }];
  }
} else {
  // NL mode: нужен message
  if (!message || message.length < 2) {
    return [{ json: { valid: 0, error: 'Введите сообщение' } }];
  }
  if (message.length > 4000) {
    return [{ json: { valid: 0, error: 'Слишком длинный запрос (максимум 4000 символов)' } }];
  }
}

if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{ json: { valid: 0, error: 'session_id содержит недопустимые символы' } }];
}

const token = String(body.token || '').trim();
if (!/^[a-f0-9]{64}$/.test(token)) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}

const workspace_slug = String(body.workspace_slug || '').trim();
const plane_url = String(body.plane_url || '').trim().replace(/\/$/, '');
const plane_token = String(body.plane_token || '').trim();

if (!workspace_slug || !plane_url || !plane_token) {
  return [{ json: { valid: 0, error: 'Plane не настроен', plane_setup_required: true } }];
}
if (!/^[a-z0-9_-]{1,64}$/i.test(workspace_slug)) {
  return [{ json: { valid: 0, error: 'workspace_slug содержит недопустимые символы' } }];
}
if (!/^https?:\/\//.test(plane_url)) {
  return [{ json: { valid: 0, error: 'plane_url должен начинаться с http:// или https://' } }];
}

// HIGH-3 fix: пробрасываем sticky_project в дальнейший pipeline для LLM-промпта
const sticky_project = String(body.sticky_project || '').trim();
const out = { valid: 1, session_id, token, workspace_slug, plane_url, plane_token, sticky_project };
if (is_direct) {
  out.is_direct = 1;
  out.direct_action = directAction;
  out.direct_params = (body.params && typeof body.params === 'object') ? body.params : {};
  out.message = '[direct: ' + directAction + ']';
} else {
  out.is_direct = 0;
  out.message = message;
}
return [{ json: out }];

// Token result: если SQL вернул user_id — сессия валидна, иначе 401.
const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id, username: data.username } }];

// Собираем projects[] из ответа Plane (пагинированный объект или массив).
// Передаём дальше как контекст для LLM (чтобы понимал, какие проекты есть).
const raw = $input.first().json || {};
const src = $('Token result').first().json;
let projects = [];
if (Array.isArray(raw)) {
  projects = raw;
} else if (Array.isArray(raw.results)) {
  projects = raw.results;
} else if (raw.error || raw.detail) {
  // HIGH-3 fix: вместо silent plane_error - шорткат в chat-ветку с сообщением.
  const errMsg = raw.error || raw.detail || 'Plane API недоступен';
  return [{ json: { ...src, action: 'chat', params: {}, is_direct: 1, direct_action: 'chat', llm_text: 'Plane недоступен: ' + String(errMsg).slice(0,200), projects: [] } }];
}
const projectsSlim = projects.map(p => ({
  id: p.id,
  name: p.name,
  identifier: p.identifier
}));
return [{ json: { ...src, projects: projectsSlim } }];

// Direct-bypass: action/params взяты прямо из body запроса, LLM пропускаем.
// Резолвим project_name → project_id (как Parse LLM) и кидаем дальше в Switch.
const src = $input.first().json;
const action = src.direct_action;
const params = src.direct_params || {};

// Резолв project_name → project_id (case-insensitive)
let project_id = null;
let project_name_canonical = null;
if (params.project_name) {
  const wanted = String(params.project_name).toLowerCase();
  const found = (src.projects || []).find(p => String(p.name || '').toLowerCase() === wanted);
  if (found) {
    project_id = found.id;
    project_name_canonical = found.name;
  }
}

const NEEDS_PROJECT = new Set(['list_issues','create_issue','update_issue','delete_issue','search_issues','change_status','set_deadline','add_comment','get_issue']);
if (NEEDS_PROJECT.has(action) && !project_id) {
  const available = (src.projects || []).map(p => p.name).join(', ') || '— у вас нет проектов';
  return [{ json: {
    ...src,
    action: 'chat',
    params: {},
    llm_text: `Не нашёл проект «${params.project_name || '—'}». Доступные: ${available}.`
  } }];
}

return [{ json: { ...src, action, params, project_id, project_name_canonical, llm_text: `Direct: ${action}.` } }];

// Парсим LLM-ответ → action/params/text. LLM иногда оборачивает JSON в ```json...```
// или добавляет лишний текст. Идём от строгого parse к фоллбекам.
const raw = $input.first().json;
const src = $('Контекст: проекты').first().json;

function extractText(raw) {
  if (!raw) return '';
  // openAi-node ответ: output[0].content[0].text
  if (raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0]) {
    return String(raw.output[0].content[0].text || '');
  }
  // Запасной формат
  if (raw.choices && raw.choices[0] && raw.choices[0].message) {
    return String(raw.choices[0].message.content || '');
  }
  return '';
}

const text = extractText(raw).trim();
if (!text) {
  return [{ json: { ...src, action: 'chat', params: {}, llm_text: 'Не удалось получить ответ от LLM. Попробуйте ещё раз.', llm_error: true } }];
}

function tryParse(s) {
  try { return JSON.parse(s); } catch(_) { return null; }
}

let parsed = tryParse(text);
if (!parsed) {
  // Срезаем ```json ... ``` обёртку
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) parsed = tryParse(m[1].trim());
}
if (!parsed) {
  // Берём первый {...} в строке
  const m2 = text.match(/\{[\s\S]*\}/);
  if (m2) parsed = tryParse(m2[0]);
}

if (!parsed || typeof parsed !== 'object') {
  // LLM ушёл в свободный текст — трактуем как chat
  return [{ json: { ...src, action: 'chat', params: {}, llm_text: text } }];
}

const ALLOWED = new Set(['list_projects','list_issues','create_issue','update_issue','delete_issue','search_issues','change_status','assign_issue','set_deadline','add_label','remove_label','add_comment','get_issue','bulk','stats','cross_project_search','list_comments','list_members','list_cycles','list_modules','list_notifications','list_activity','create_epic','me','chat']);
const action = ALLOWED.has(parsed.action) ? parsed.action : 'chat';
const params = (parsed.params && typeof parsed.params === 'object') ? parsed.params : {};
const llm_text = String(parsed.text || '').trim() || 'Готово.';
const quick_replies = Array.isArray(parsed.quick_replies) ? parsed.quick_replies.slice(0, 6) : null;

// Резолвим project_name → project_id (case-insensitive)
let project_id = null;
let project_name_canonical = null;
if (params.project_name) {
  const wanted = String(params.project_name).toLowerCase();
  const found = (src.projects || []).find(p => String(p.name || '').toLowerCase() === wanted);
  if (found) {
    project_id = found.id;
    project_name_canonical = found.name;
  }
}

// Если для action нужен project_id, но не нашли — даунгрейд до chat с подсказкой
const NEEDS_PROJECT = new Set(['list_issues','create_issue','update_issue','delete_issue','search_issues']);
if (NEEDS_PROJECT.has(action) && !project_id) {
  // BUG-FIX: пустой/мусорный project_name + list_issues → reroute на
  // cross_project_search (поиск задач по всем проектам). Раньше падало
  // в chat-фоллбэк «Не нашёл проект __» хотя юзер просил «все задачи».
  const rawName = String(params.project_name || '').trim().toLowerCase();
  const isEmptyName = !rawName || rawName === '__' || rawName === 'all' || rawName === 'все' || rawName === 'любой';
  if (isEmptyName && action === 'list_issues') {
    return [{ json: { ...src, action: 'cross_project_search', params: { query: '' }, project_id: null, project_name_canonical: null, llm_text: 'Покажу задачи по всем проектам.', quick_replies } }];
  }
  const available = (src.projects || []).map(p => p.name).join(', ') || '— у вас нет проектов';
  return [{ json: {
    ...src,
    action: 'chat',
    params: {},
    llm_text: `Не нашёл проект «${params.project_name || '—'}». Доступные проекты: ${available}.`
  } }];
}

return [{ json: { ...src, action, params, project_id, project_name_canonical, llm_text, quick_replies } }];

// list_projects: данные уже есть в $json.projects (фетчили в Контекст: проекты).
const src = $input.first().json;
return [{ json: { ...src, api_result: { projects: src.projects || [] }, api_ok: true } }];

