}, ($json.params.target_date && /^\d{4}-\d{2}-\d{2}$/.test($json.params.target_date)) ? { target_date: $json.params.target_date } : {}, ($json.params.start_date && /^\d{4}-\d{2}-\d{2}$/.test($json.params.start_date)) ? { start_date: $json.params.start_date } : {})) }}

