// Перед update/delete нужно найти issue_id по issue_name. Делаем GET issues + find.
// Возвращаем json с issue_id или ошибку.
const src = $input.first().json;
const issueName = String((src.params && src.params.issue_name) || '').trim().toLowerCase();
if (!issueName) {
  return [{ json: { ...src, _resolve_error: 'Не указано название задачи' } }];
}
const url = `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/issues/?per_page=100`;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET', url, headers: {
      'X-API-Key': src.plane_token,
      'Content-Type': 'application/json'
    }, timeout: 15000, json: true
  });
  const issues = Array.isArray(resp) ? resp : (resp.results || []);
  const found = issues.find(i => String(i.name || '').toLowerCase() === issueName);
  if (!found) {
    return [{ json: { ...src, _resolve_error: `Задача «${src.params.issue_name}» не найдена в проекте ${src.project_name_canonical}` } }];
  }
  return [{ json: { ...src, issue_id: found.id, issue_name_canonical: found.name } }];
} catch (e) {
  return [{ json: { ...src, _resolve_error: 'Ошибка поиска задачи: ' + (e.message || e) } }];
}

