})()) }}

parameters.jsCode:
// delete: тот же resolve issue_id что и в update, отдельная нода для чистоты графа.
const src = $input.first().json;
const issueName = String((src.params && src.params.issue_name) || '').trim().toLowerCase();
if (!issueName) {
  return [{ json: { ...src, _resolve_error: 'Не указано название задачи' } }];
}
const url = `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/issues/?per_page=100`;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET', url, headers: {
      'X-API-Key': src.plane_token,
      'Content-Type': 'application/json'
    }, timeout: 15000, json: true
  });
  const issues = Array.isArray(resp) ? resp : (resp.results || []);
  const found = issues.find(i => String(i.name || '').toLowerCase() === issueName);
  if (!found) {
    return [{ json: { ...src, _resolve_error: `Задача «${src.params.issue_name}» не найдена в проекте ${src.project_name_canonical}` } }];
  }
  return [{ json: { ...src, issue_id: found.id, issue_name_canonical: found.name } }];
} catch (e) {
  return [{ json: { ...src, _resolve_error: 'Ошибка поиска задачи: ' + (e.message || e) } }];
}

// Единый форматтер. Также: HIGH-1 — реальная итерация bulk через helpers.httpRequest,
// HIGH-4 — project_name_canonical в data для sticky, HIGH-5 — quick_replies passthrough.
function getSrc() {
  try { return $('Parse LLM').first().json; } catch(_) {}
  try { return $('Direct resolve').first().json; } catch(_) {}
  return {};
}
const src = getSrc();
const input = $input.first().json || {};
const action = src.action || 'chat';
const PATCH_ACTIONS = ['change_status','assign_issue','set_deadline','add_label','remove_label'];
const PRIO_RU = {urgent:'срочный',high:'высокий',medium:'средний',low:'низкий',none:'не задан'};
const STATE_RU_GROUP = {backlog:'Отложенные',unstarted:'Запланированные',started:'В работе',completed:'Готово',cancelled:'Отменено'};
function _stateRu(stD){ if(!stD) return '?'; const g = stD.group || ''; return STATE_RU_GROUP[g] || stD.name || '?'; }

const llm_text = src.llm_text || '';
const quick_replies = src.quick_replies || null;

const PASSTHROUGH_ACTIONS = new Set(['stats','cross_project_search','list_comments','me','list_members','list_cycles','list_modules','list_notifications','list_activity','create_epic']);
// Если действие уже обработано в Stats/CrossProject handler — input уже
// содержит финальный {response, action, data}. Не перетираем — пробрасываем.
if (PASSTHROUGH_ACTIONS.has(action) && input && (input.response || input.data || input.action === action)) {
  const out = {
    response: input.response || llm_text || 'Готово.',
    action: input.action || action,
    data: input.data || null
  };
  if (input.error) out.error = input.error;
  if (src.project_name_canonical && out.data && !out.data.project_name_canonical) {
    out.data.project_name_canonical = src.project_name_canonical;
  }
  if (quick_replies) out.quick_replies = quick_replies;
  return [{ json: out }];
}



function planeError(r) {
  if (!r || typeof r !== 'object') return null;
  if (r.error && typeof r.error === 'object') {
    const e = r.error;
    const status = e.status || (e.response && e.response.status) || e.httpCode;
    if (status === 429) return 'Plane перегружен запросами. Подожди 5-10 секунд и попробуй снова.';
    if (status === 401 || status === 403) return 'Plane: нет доступа (проверь API token в настройках).';
    if (status === 404) return 'Plane: задача или проект не найдены.';
    if (status === 400) return 'Plane: некорректные данные запроса.';
    if (status >= 500) return 'Plane: внутренняя ошибка сервера (' + status + ').';
    if (e.message) return String(e.message).split(String.fromCharCode(10))[0].slice(0, 200);
  }
  if (r.error && typeof r.error === 'string') return r.error.split(String.fromCharCode(10))[0].slice(0, 200);
  if (r.detail) return String(r.detail).slice(0, 200);
  return null;
}

function wrap(out) {
  out.data = out.data || {};
  if (src.project_name_canonical && !out.data.project_name_canonical) {
    out.data.project_name_canonical = src.project_name_canonical;
  }
  if (quick_replies && !out.quick_replies) {
    out.quick_replies = quick_replies;
  }
  return [{ json: out }];
}

if (action === 'chat' || src.llm_error) {
  return wrap({ response: llm_text || 'Готово.', action: 'chat', data: null });
}

function getResolveError() {
  if (action === 'update_issue') {
    try { return $('update: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  } else if (action === 'delete_issue') {
    try { return $('delete: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  }
  return null;
}
const resolveErr = getResolveError() || input._resolve_error;
if (resolveErr) {
  const dis = (input && input._disambiguation) ||
              (function(){ try { return $('update: resolve issue_id').first().json._disambiguation; } catch(_) {} })() ||
              (function(){ try { return $('delete: resolve issue_id').first().json._disambiguation; } catch(_) {} })();
  const out = { response: resolveErr, action, data: null, error: resolveErr };
  if (dis) out.disambiguation = dis;
  return wrap(out);
}

if (action === 'list_projects') {
  const projects = (input.api_result && input.api_result.projects) || src.projects || [];
  return wrap({
    response: llm_text + (projects.length === 0 ? '\n\nНет доступных проектов.' : ''),
    action,
    data: { projects: projects.map(p => ({ id: p.id, name: p.name, identifier: p.identifier })) }
  });
}

if (action === 'list_issues' || action === 'search_issues') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось получить задачи: ' + err, action, data: null, error: err });
  let issues = Array.isArray(input) ? input : (input.results || []);
  const _statesMap = input._states_map || null;
  const _projectId = input._project_id || null;
  if (action === 'search_issues') {
    const q = String((src.params && src.params.query) || '').toLowerCase().trim();
    if (q) issues = issues.filter(i => String(i.name || '').toLowerCase().includes(q));
  }
  return wrap({
    response: llm_text + (issues.length === 0 ? '\n\nЗадач не найдено.' : ('\n\nНайдено: ' + issues.length + '.')),
    action,
    data: {
      project: src.project_name_canonical,
      states_map: _statesMap,
      project_id: _projectId,
      issues: issues.map(i => ({
        id: i.id, name: i.name, priority: i.priority,
        state: i.state, state_detail: i.state_detail,
        sequence_id: i.sequence_id, created_at: i.created_at,
        target_date: i.target_date, start_date: i.start_date,
        assignees: i.assignees, labels: i.labels,
        comments_count: i.comments_count,
        description_html: i.description_html
      }))
    }
  });
}

if (action === 'create_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось создать задачу: ' + err, action, data: null, error: err });
  return wrap({
    response: llm_text + ' Задача создана: ' + input.name + '.',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority } }
  });
}

if (action === 'update_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось обновить задачу: ' + err, action, data: null, error: err });
  return wrap({
    response: llm_text + ' Задача обновлена: ' + (input.name || src.params.issue_name) + '.',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority } }
  });
}

if (action === 'delete_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось удалить задачу: ' + err, action, data: null, error: err });
  return wrap({ response: llm_text + ' Задача удалена.', action, data: null });
}

if (action === 'get_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось получить задачу: ' + err, action, data: null, error: err });
  return wrap({
    response: 'Задача «' + input.name + '». '
       + 'Приоритет: ' + (PRIO_RU[String(input.priority||'none').toLowerCase()] || input.priority || 'не задан') + '. '
       + 'Статус: ' + _stateRu(input.state_detail) + '. '
       + (input.target_date ? 'Срок: ' + input.target_date + '. ' : '')
       + (input.start_date ? 'Начало: ' + input.start_date + '. ' : '')
       + (input.created_at ? 'Создана: ' + String(input.created_at).slice(0,10) + '. ' : '')
       + (input.description_html ? 'Описание: ' + String(input.description_html).replace(/<[^>]+>/g,'').slice(0,200) : ''),
    action,
    data: { issue: input }
  });
}

if (PATCH_ACTIONS.includes(action)) {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось обновить задачу: ' + err, action, data: null, error: err });
  const labels = { change_status: 'Статус', assign_issue: 'Исполнители', set_deadline: 'Срок', add_label: 'Метки', remove_label: 'Метки' };
  return wrap({
    response: (labels[action] || 'Поле') + ' обновлено для «' + (input.name || src.params.issue_name) + '».',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority, state: input.state, target_date: input.target_date, assignees: input.assignees, labels: input.labels } }
  });
}

if (action === 'add_comment') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось добавить комментарий: ' + err, action, data: null, error: err });
  return wrap({
    response: 'Комментарий добавлен к «' + src.params.issue_name + '».',
    action,
    data: { comment: { id: input.id, comment_html: input.comment_html } }
  });
}

// HIGH-1: bulk — реальная итерация через helpers.httpRequest
if (action === 'bulk') {
  const subActions = (src.params && Array.isArray(src.params.actions)) ? src.params.actions : [];
  if (!subActions.length) {
    return wrap({ response: 'Bulk: нет операций.', action: 'bulk', data: null });
  }
  const projectsCache = src.projects || [];
  const issuesByProject = {};
  function findProjectId(projectName) {
    if (!projectName) return null;
    const p = projectsCache.find(p => String(p.name).toLowerCase() === String(projectName).toLowerCase());
    return p ? p.id : null;
  }
  async function getIssues(projectId) {
    if (issuesByProject[projectId]) return issuesByProject[projectId];
    try {
      const r = await this.helpers.httpRequest({
        method: 'GET',
        url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projectId + '/issues/?per_page=100&expand=state_detail',
        headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
        timeout: 15000, json: true
      });
      issuesByProject[projectId] = Array.isArray(r) ? r : (r.results || []);
      return issuesByProject[projectId];
    } catch (e) { issuesByProject[projectId] = []; return []; }
  }
  let statesCache = null;
  async function getStates(projectId) {
    if (statesCache && statesCache.projectId === projectId) return statesCache.list;
    try {
      const r = await this.helpers.httpRequest({
        method: 'GET',
        url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projectId + '/states/',
        headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
        timeout: 15000, json: true
      });
      const list = Array.isArray(r) ? r : (r.results || []);
      statesCache = { projectId, list };
      return list;
    } catch (e) { return []; }
  }

  const results = [];
  for (const sub of subActions) {
    const subAct = sub.action;
    const p = sub.params || {};
    const projId = findProjectId(p.project_name);
    if (!projId) { results.push({ action: subAct, ok: false, error: 'project not found: ' + p.project_name }); continue; }
    try {
      if (subAct === 'create_issue') {
        const body = { name: p.name || 'Без названия', priority: p.priority || 'none' };
        if (p.target_date && /^\d{4}-\d{2}-\d{2}$/.test(p.target_date)) body.target_date = p.target_date;
        if (p.description) body.description_html = '<p>' + String(p.description).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</p>';
        const r = await this.helpers.httpRequest({
          method: 'POST',
          url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/',
          headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
          body: body, timeout: 15000, json: true
        });
        results.push({ action: subAct, ok: true, name: r.name });
        delete issuesByProject[projId];
      } else if (subAct === 'delete_issue' || subAct === 'change_status' || subAct === 'update_issue' || subAct === 'add_comment' || subAct === 'set_deadline') {
        const issues = await getIssues.call(this, projId);
        const found = issues.find(i => String(i.name || '').toLowerCase() === String(p.issue_name || '').toLowerCase());
        if (!found) { results.push({ action: subAct, ok: false, error: 'issue not found: ' + p.issue_name }); continue; }
        if (subAct === 'delete_issue') {
          await this.helpers.httpRequest({
            method: 'DELETE',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            timeout: 15000, json: true
          });
          delete issuesByProject[projId];
        } else if (subAct === 'change_status') {
          const states = await getStates.call(this, projId);
          const ALIASES = {'todo':'unstarted','to do':'unstarted','to_do':'unstarted','in progress':'started','in_progress':'started','wip':'started','работа':'started','в работе':'started','done':'completed','completed':'completed','готово':'completed','cancelled':'cancelled','canceled':'cancelled','отменено':'cancelled','backlog':'backlog','отложено':'backlog','отложенные':'backlog'};
          const wantedRaw = String(p.state || '').toLowerCase().replace(/_/g, ' ');
          const wantedGroup = ALIASES[wantedRaw] || wantedRaw;
          const target = states.find(s => String(s.group||'').toLowerCase() === wantedGroup)
                      || states.find(s => String(s.name||'').toLowerCase() === wantedRaw);
          if (!target) { results.push({ action: subAct, ok: false, error: 'state not found: ' + p.state }); continue; }
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: { state: target.id }, timeout: 15000, json: true
          });
          delete issuesByProject[projId];
        } else if (subAct === 'set_deadline') {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: { target_date: (p.target_date && /^\d{4}-\d{2}-\d{2}$/.test(p.target_date)) ? p.target_date : null }, timeout: 15000, json: true
          });
        } else if (subAct === 'update_issue') {
          const upd = {};
          if (p.name) upd.name = p.name;
          if (p.priority) upd.priority = p.priority;
          if (p.target_date) upd.target_date = p.target_date;
          if (p.description) upd.description_html = '<p>' + p.description + '</p>';
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: upd, timeout: 15000, json: true
          });
        } else if (subAct === 'add_comment') {
          await this.helpers.httpRequest({
            method: 'POST',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/comments/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: { comment_html: '<p>' + (p.comment || '') + '</p>' }, timeout: 15000, json: true
          });
        }
        results.push({ action: subAct, ok: true, name: found.name });
      } else {
        results.push({ action: subAct, ok: false, error: 'unsupported in bulk: ' + subAct });
      }
    } catch (e) {
      results.push({ action: subAct, ok: false, error: String(e.message || e).slice(0, 100) });
    }
  }
  const ok = results.filter(r => r.ok).length;
  const fail = results.length - ok;
  return wrap({
    response: 'Bulk: ' + ok + ' успешно, ' + fail + ' с ошибкой' + (fail > 0 ? '. Детали: ' + results.filter(r=>!r.ok).map(r=>r.action+'/'+r.error).slice(0,3).join('; ') : '') + '.',
    action: 'bulk',
    data: { results: results }
  });
}

return wrap({ response: llm_text || 'Готово.', action, data: null });

const src = $input.first().json;
try {
  const issue = await this.helpers.httpRequest({
    method: 'GET',
    url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + src.project_id + '/issues/' + src.issue_id + '/',
    headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
    timeout: 10000, json: true
  });
  let states = [];
  try {
    const respS = await this.helpers.httpRequest({
      method: 'GET',
      url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + src.project_id + '/states/',
      headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
      timeout: 10000, json: true
    });
    states = Array.isArray(respS) ? respS : (respS.results || []);
  } catch (_) {}
  const stateMap = {};
  states.forEach(function(s){ stateMap[s.id] = { name: s.name, group: s.group, color: s.color }; });
  return [{ json: Object.assign({}, issue, { state_detail: stateMap[issue.state] || null }) }];
} catch (e) {
  return [{ json: { error: { message: e.message || String(e), status: e.statusCode || (e.response && e.response.status) || 500 } } }];
}

// Resolve для extended-actions: GET issues (для issue_id), GET states при
// action=change_status (для state_id), резолв labels (id уже в params).
const src = $input.first().json;
const params = src.params || {};
const wantedIssue = String(params.issue_name || '').toLowerCase().trim();

if (!wantedIssue) {
  return [{ json: { ...src, _resolve_error: 'Не указано название задачи (issue_name)' } }];
}

let issues = [];
try {
  const respI = await this.helpers.httpRequest({
    method: 'GET',
    url: `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/issues/?per_page=100`,
    headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
    timeout: 15000, json: true
  });
  issues = Array.isArray(respI) ? respI : (respI.results || []);
} catch (e) {
  return [{ json: { ...src, _resolve_error: 'Не удалось получить задачи: ' + (e.message || e) } }];
}

const issue_obj = issues.find(i => String(i.name || '').toLowerCase() === wantedIssue);
if (!issue_obj) {
  const available = issues.slice(0,5).map(i => i.name).join(', ') || '—';
  return [{ json: { ...src, _resolve_error: `Не нашёл задачу «${params.issue_name}». Доступные: ${available}` } }];
}
const issue_id = issue_obj.id;

// Для change_status — GET states и резолв state_id
let state_id = null;
if (src.action === 'change_status' && params.state) {
  let states = [];
  try {
    const respS = await this.helpers.httpRequest({
      method: 'GET',
      url: `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/states/`,
      headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
      timeout: 15000, json: true
    });
    states = Array.isArray(respS) ? respS : (respS.results || []);
  } catch (e) {
    return [{ json: { ...src, _resolve_error: 'Не удалось получить states: ' + (e.message || e) } }];
  }
  const wantedState = String(params.state).toLowerCase().trim().replace(/_/g, ' ');
  const stateByName = states.find(s => String(s.name || '').toLowerCase() === wantedState);
  const stateByGroup = states.find(s => String(s.group || '').toLowerCase() === wantedState);
  const ALIASES = {
    'тудо':'unstarted','todo':'unstarted','к выполнению':'unstarted','новая':'unstarted',
    'в работе':'started','в процессе':'started','in progress':'started','делается':'started',
    'готово':'completed','done':'completed','завершено':'completed','выполнено':'completed',
    'отменено':'cancelled','cancelled':'cancelled','отмена':'cancelled',
    'бэклог':'backlog','backlog':'backlog','очередь':'backlog'
  };
  const aliased = ALIASES[wantedState];
  const stateByAlias = aliased ? states.find(s => String(s.group || '').toLowerCase() === aliased) : null;
  const stateFuzzy = (!stateByName && !stateByGroup && !stateByAlias) ? states.find(function(s){return String(s.name||'').toLowerCase().includes(wantedState)}) : null;
  const state = stateByName || stateByGroup || stateByAlias || stateFuzzy;  // MED-8 fuzzy
  if (state) state_id = state.id;
  else return [{ json: { ...src, _resolve_error: `Не нашёл state «${params.state}». Доступные: ${states.map(s=>s.name).join(', ')}` } }];
}

return [{ json: { ...src, issue_id, issue_obj, state_id } }];

// Enrich issues со state_group через GET /states/ — Plane v0.27 не поддерживает
// ?expand=state_detail.
//
// ROOT-FIX: НЕ возвращаем ошибку при провале enrich. Просто отдаём issues
// с полем `state` (UUID). Frontend кэширует state-map в localStorage и
// сам восстановит state_detail из cache. Это гарантирует, что rapid
// Обновить + перегрузка Plane больше НЕ приводят к коллапсу всех задач
// в одну колонку.
let src = {};
try { src = $('Direct resolve').first().json; } catch(_) {}
if (!src || !src.project_id) { try { src = $('Parse LLM').first().json; } catch(_) {} }
const input = $input.first().json || {};
const issues = Array.isArray(input) ? input : (input.results || []);

let states = [];
const delays = [0, 500, 1500];
for (let attempt = 0; attempt < delays.length; attempt++) {
  if (delays[attempt]) await new Promise(r => setTimeout(r, delays[attempt]));
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/states/`,
      headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
      timeout: 10000, json: true
    });
    states = Array.isArray(resp) ? resp : (resp.results || []);
    if (states.length) break;
  } catch (e) { /* continue */ }
}

const stateMap = {};
states.forEach(s => { stateMap[s.id] = { id: s.id, name: s.name, group: s.group, color: s.color }; });

// Enrich. Если state_detail не найден — оставляем null, но `state` UUID
// в issue ОБЯЗАТЕЛЬНО присутствует чтобы фронт мог использовать своё кэшированное
// state-mapping.
const enriched = issues.map(i => ({
  ...i,
  state_detail: stateMap[i.state] || null
}));

// Дополнительно прокидываем весь state-map отдельным полем data.states —
// frontend сохранит его в localStorage per project, и на следующих
// загрузках сможет резолвить state_detail даже если enrich упал.
return [{ json: { results: enriched, _enriched: true, _states_map: stateMap, _project_id: src.project_id } }];

// Формируем строку history для LLM. Берём последние 6 пар (user+assistant)
// = 12 сообщений в обратном порядке (свежие первыми из SQL).
// ВАЖНО: для newline в join() используем String.fromCharCode(10), НЕ '\n' —
// иначе при JSON-deserialize литерал \n становится настоящим LF, который
// ломает строку-литерал JS → Syntax Error.
const rows = $input.all().map(i => i.json).filter(r => r.role && r.content);
const src = $('Контекст: проекты').first().json;
const NL = String.fromCharCode(10);
const lines = rows.slice(0, 12).reverse().map(r => {
  const c = String(r.content).slice(0, 300);
  return (r.role === 'user' ? 'Юзер: ' : 'Plane-агент: ') + c;
});
const historyContext = lines.length ? lines.join(NL) : '';
return [{ json: Object.assign({}, src, { historyContext: historyContext }) }];

// Plane: stats/cross_project_search/list_comments/me handler.
// Делает API-вызовы через helpers.httpRequest, агрегирует результаты,
// возвращает уже отформатированный ответ для Формат ответа.
const src = $input.first().json;
const params = src.params || {};
const action = src.action;
const planeUrl = src.plane_url;
const planeToken = src.plane_token;
const slug = src.workspace_slug;
const NL = String.fromCharCode(10);

async function getProjects() {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/?per_page=100',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 15000, json: true
    });
    return Array.isArray(r) ? r : (r.results || []);
  } catch (e) { return []; }
}
async function getIssues(projectId) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + projectId + '/issues/?per_page=100&expand=state_detail',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 15000, json: true
    });
    return Array.isArray(r) ? r : (r.results || []);
  } catch (e) { return []; }
}

// === me: GET /api/v1/users/me/ ===
if (action === 'me') {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/users/me/',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 15000, json: true
    });
    return [{ json: {
      response: 'Текущий пользователь: ' + (r.display_name || r.email || r.id || '—'),
      action: 'me',
      data: { user_id: r.id, display_name: r.display_name, email: r.email }
    } }];
  } catch (e) {
    return [{ json: { response: 'Не удалось получить пользователя: ' + (e.message || e), action: 'me', data: null, error: 'me_fetch_failed' } }];
  }
}

// === list_members: пробуем разные endpoint'ы, fallback на /users/me/ ===
if (action === 'list_members') {
  let raw = null, errMsg = null;
  const slugUrls = [
    planeUrl + '/api/v1/workspaces/' + slug + '/members/?expand=member',
    planeUrl + '/api/v1/workspaces/' + slug + '/members/',
    planeUrl + '/api/v1/workspaces/' + slug + '/workspace-members/?expand=member',
    planeUrl + '/api/v1/workspaces/' + slug + '/workspace-members/'
  ];
  // Сначала workspace-level
  for (const u of slugUrls) {
    try {
      raw = await this.helpers.httpRequest({
        method: 'GET',
        url: u,
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        timeout: 15000, json: true
      });
      if (raw) break;
    } catch (e) { errMsg = String(e.message || e); raw = null; }
  }

  // Если workspace-level не работает — пробуем project-level (для каждого проекта)
  if (!raw) {
    try {
      const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
      const aggregated = [];
      const seenIds = new Set();
      for (const p of allProjects.slice(0, 10)) {  // максимум 10 проектов чтобы не упереться в rate-limit
        try {
          const pr = await this.helpers.httpRequest({
            method: 'GET',
            url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/members/?expand=member',
            headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
            timeout: 10000, json: true
          });
          const list = Array.isArray(pr) ? pr : (pr.results || []);
          list.forEach(m => {
            const u = (typeof m.member === 'object' && m.member !== null) ? m.member : m;
            const uid = u.id || (typeof m.member === 'string' ? m.member : m.id);
            if (uid && !seenIds.has(uid)) { seenIds.add(uid); aggregated.push(m); }
          });
        } catch (_) { /* try next project */ }
      }
      if (aggregated.length) raw = { results: aggregated };
    } catch (_) {}
  }

  // Последний fallback — /users/me/ (хоть имя текущего юзера будет)
  if (!raw) {
    try {
      const me = await this.helpers.httpRequest({
        method: 'GET',
        url: planeUrl + '/api/v1/users/me/',
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        timeout: 10000, json: true
      });
      if (me && me.id) raw = { results: [{ member: me }] };
    } catch (_) {}
  }

  if (!raw) {
    return [{ json: { response: 'Не удалось загрузить участников: ' + (errMsg || 'все endpoint\'ы недоступны'), action: 'list_members', data: null, error: 'members_fetch_failed' } }];
  }
  const list = Array.isArray(raw) ? raw : (raw.results || []);
  const members = list.map(m => {
    const u = (typeof m.member === 'object' && m.member !== null) ? m.member : m;
    let userId = u.id;
    if (!userId && typeof m.member === 'string') userId = m.member;
    if (!userId) userId = m.member_id || m.user_id || m.id;
    const dn = u.display_name || m.member_display_name
            || (u.first_name && u.last_name ? (u.first_name + ' ' + u.last_name) : '')
            || u.first_name || m.member_first_name
            || u.email || m.member_email
            || '';
    return {
      id: userId,
      display_name: dn,
      first_name: u.first_name || m.member_first_name || '',
      last_name: u.last_name || m.member_last_name || '',
      email: u.email || m.member_email || '',
      avatar: u.avatar || m.member_avatar || ''
    };
  }).filter(m => m.id);
  return [{ json: {
    response: 'Участников: ' + members.length,
    action: 'list_members',
    data: { members: members }
  } }];
}

// === list_cycles: GET /api/v1/workspaces/{slug}/projects/{id}/cycles/ ===
if (action === 'list_cycles') {
  const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  const projName = String(params.project_name || '').toLowerCase();
  const proj = allProjects.find(p => String(p.name).toLowerCase() === projName);
  if (!proj) {
    return [{ json: { response: 'Проект не найден: ' + params.project_name, action: 'list_cycles', data: null, error: 'project_not_found' } }];
  }
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/cycles/?per_page=100',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 15000, json: true
    });
    const cycles = Array.isArray(r) ? r : (r.results || []);
    // Подтягиваем задачи каждого цикла (но не более чем для первых 20)
    const enriched = [];
    for (const c of cycles.slice(0, 20)) {
      let cycleIssues = [];
      try {
        const ci = await this.helpers.httpRequest({
          method: 'GET',
          url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/cycles/' + c.id + '/cycle-issues/?per_page=100',
          headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
          timeout: 10000, json: true
        });
        cycleIssues = Array.isArray(ci) ? ci : (ci.results || []);
      } catch (_) {}
      enriched.push({
        id: c.id, name: c.name, description: c.description,
        start_date: c.start_date, end_date: c.end_date,
        owned_by: c.owned_by,
        total_issues: c.total_issues || cycleIssues.length,
        completed_issues: c.completed_issues,
        issue_ids: cycleIssues.map(i => i.issue || i.id).slice(0, 50)
      });
    }
    return [{ json: {
      response: 'Циклов в проекте «' + proj.name + '»: ' + cycles.length,
      action: 'list_cycles',
      data: { cycles: enriched, project_id: proj.id, project_name_canonical: proj.name }
    } }];
  } catch (e) {
    return [{ json: { response: 'Не удалось загрузить циклы: ' + (e.message || e), action: 'list_cycles', data: null, error: 'cycles_fetch_failed' } }];
  }
}

// === list_modules: GET /api/v1/workspaces/{slug}/projects/{id}/modules/ ===
if (action === 'list_modules') {
  const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  const projName = String(params.project_name || '').toLowerCase();
  const proj = allProjects.find(p => String(p.name).toLowerCase() === projName);
  if (!proj) {
    return [{ json: { response: 'Проект не найден: ' + params.project_name, action: 'list_modules', data: null, error: 'project_not_found' } }];
