    return [{ json: { response: 'Не удалось загрузить модули: ' + (e.message || e), action: 'list_modules', data: null, error: 'modules_fetch_failed' } }];
  }
}

// === list_notifications: сначала пробуем родной API, фоллбэк на activity-feed.
// ROOT-FIX: Plane v0.27 не выставляет /notifications/, поэтому строим
// синтетические уведомления из ленты активности (issue-activity) — события,
// в которых пользователь упомянут (assignees, @-mention в комментариях,
// state/target_date/priority изменения на задачах где он assignee).
if (action === 'list_notifications') {
  // 1. Сначала пытаемся родной endpoint (если на новых версиях появится).
  const nativeUrls = [
    planeUrl + '/api/v1/workspaces/' + slug + '/users/notifications/?per_page=50',
    planeUrl + '/api/v1/workspaces/' + slug + '/notifications/?per_page=50',
    planeUrl + '/api/v1/users/me/notifications/?per_page=50'
  ];
  for (const u of nativeUrls) {
    try {
      const raw = await this.helpers.httpRequest({
        method: 'GET', url: u,
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        timeout: 10000, json: true
      });
      if (raw) {
        const list = Array.isArray(raw) ? raw : (raw.results || []);
        if (list.length) {
          const notifications = list.slice(0, 50).map(n => ({
            id: n.id,
            title: n.title || (n.data && n.data.issue && n.data.issue.name) || '',
            message: n.message || (n.data && n.data.issue_activity && n.data.issue_activity.comment) || '',
            triggered_by: n.triggered_by_details || n.triggered_by || null,
            data: n.data || {},
            read_at: n.read_at,
            created_at: n.created_at,
            project: n.project,
            type: (n.data && n.data.issue_activity && n.data.issue_activity.field) || 'event'
          }));
          const unread = notifications.filter(n => !n.read_at).length;
          return [{ json: {
            response: 'Уведомлений: ' + notifications.length + (unread ? ' (непрочитанных: ' + unread + ')' : ''),
            action: 'list_notifications',
            data: { notifications: notifications, unread: unread, source: 'native' }
          } }];
        }
      }
    } catch (_) { /* try next */ }
  }

  // 2. Fallback: строим из activity-feed.
  let meId = null, meName = '', meEmail = '';
  try {
    const me = await this.helpers.httpRequest({
      method: 'GET', url: planeUrl + '/api/v1/users/me/',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 10000, json: true
    });
    if (me && me.id) { meId = me.id; meName = me.display_name || me.first_name || ''; meEmail = me.email || ''; }
  } catch (_) {}

  const allProjectsN = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  // Идём по ~10 проектам максимум, чтобы не упереться в rate-limit.
  const projectsToScan = allProjectsN.slice(0, 10);
  const allEvents = [];
  for (const p of projectsToScan) {
    const urls = [
      planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/activity/?per_page=100',
      planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/issues-activity/?per_page=100'
    ];
    for (const u of urls) {
      try {
        const r = await this.helpers.httpRequest({
          method: 'GET', url: u,
          headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
          timeout: 10000, json: true
        });
        const list = Array.isArray(r) ? r : (r.results || []);
        list.forEach(a => { a._project = p.name; a._project_id = p.id; });
        allEvents.push.apply(allEvents, list);
        break;
      } catch (_) { /* try next endpoint */ }
    }
  }

  // Фильтр: оставляем события, ВАЖНЫЕ для текущего пользователя.
  const meIdStr = meId ? String(meId) : '';
  const meNameLow = meName.toLowerCase();
  const meEmailLow = meEmail.toLowerCase();
  function isAboutMe(a) {
    // Action не от меня (своих собственных движений не показываем)
    const actorId = String(a.actor || a.actor_id || (a.actor_detail && a.actor_detail.id) || '');
    if (actorId && meIdStr && actorId === meIdStr) return false;
    const field = String(a.field || '').toLowerCase();
    const newV = String(a.new_value || '');
    const oldV = String(a.old_value || '');
    // 1) Меня добавили в assignees
    if (field === 'assignees' && meIdStr) {
      if (newV.indexOf(meIdStr) !== -1 && oldV.indexOf(meIdStr) === -1) return true;
    }
    // 2) Меня упомянули в комментарии
    if (a.comment && (meNameLow || meEmailLow)) {
      const cLow = String(a.comment).toLowerCase();
      if (meNameLow && cLow.indexOf('@' + meNameLow) !== -1) return true;
      if (meEmailLow && cLow.indexOf('@' + meEmailLow.split('@')[0]) !== -1) return true;
      if (meNameLow && cLow.indexOf(meNameLow) !== -1) return true;
    }
    return false;
  }
  const relevant = allEvents.filter(isAboutMe);
  relevant.sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));
  const top = relevant.slice(0, 30);

  function buildTitle(a) {
    const field = String(a.field || '').toLowerCase();
    if (field === 'assignees') return 'Тебя назначили на задачу';
    if (a.comment) return 'Упоминание в комментарии';
    if (field === 'state') return 'Изменился статус';
    if (field === 'priority') return 'Изменился приоритет';
    if (field === 'target_date') return 'Изменился срок';
    return 'Событие в задаче';
  }
  function buildMessage(a) {
    if (a.comment) return String(a.comment).replace(/<[^>]+>/g, '').slice(0, 200);
    if (a.new_value) return (a.old_value ? a.old_value + ' → ' : '') + a.new_value;
    return '';
  }

  const notifications = top.map(a => ({
    id: a.id,
    title: buildTitle(a),
    message: buildMessage(a),
    triggered_by: (a.actor_detail && (a.actor_detail.display_name || a.actor_detail.email)) || a.actor || '—',
    data: { issue_id: a.issue, field: a.field, project_id: a._project_id },
    read_at: null,  // unread/read определяется фронтом через last_seen_at в localStorage
    created_at: a.created_at,
    project: a._project,
    type: a.field || 'event'
  }));

  return [{ json: {
    response: meId
      ? ('Уведомлений: ' + notifications.length + ' (на основе ленты активности)')
      : ('Не удалось определить текущего пользователя. Показано всё: ' + notifications.length),
    action: 'list_notifications',
    data: { notifications: notifications, unread: notifications.length, source: 'activity_fallback', me: { id: meId, name: meName, email: meEmail } }
  } }];
}

// === list_activity: «Что я сделал?» — история событий.
// Plane v0.27 не имеет project-level activity. События хранятся per-issue
// в /issues/{id}/activities/ (или /history/). Поэтому:
//   1. Получаем top-N недавно изменённых задач (sort by updated_at desc).
//   2. Для каждой пуллим её activities параллельно.
//   3. Сортируем общий список, отдаём топ-30.
if (action === 'list_activity') {
  const allProjectsAct = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  const projName = String(params.project_name || '').toLowerCase();
  const filterProj = projName ? allProjectsAct.filter(p => String(p.name).toLowerCase() === projName) : allProjectsAct.slice(0, 5);
  // Текущий юзер для фильтрации «мои»
  let meId = null;
  try {
    const me = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/users/me/',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 10000, json: true
    });
    meId = me && me.id;
  } catch (_) {}

  const activities = [];
  // Сколько проектов сканируем и сколько issues per project — балансируем
  // скорость vs полноту. 5 проектов × 15 issues × 1 запрос = ~75 запросов max.
  const ISSUES_PER_PROJECT = filterProj.length === 1 ? 30 : 15;
  for (const p of filterProj) {
    // 1) Пробуем project-level activity (новый Plane может выставлять)
    let gotProjectLevel = false;
    const projUrls = [
      planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/activity/?per_page=50',
      planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/issues-activity/?per_page=50'
    ];
    for (const u of projUrls) {
      try {
        const r = await this.helpers.httpRequest({
          method: 'GET', url: u,
          headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
          timeout: 8000, json: true
        });
        const list = Array.isArray(r) ? r : (r.results || []);
        if (list.length) {
          list.forEach(a => { a._project = p.name; });
          activities.push.apply(activities, list);
          gotProjectLevel = true;
          break;
        }
      } catch (_) { /* try next */ }
    }
    if (gotProjectLevel) continue;

    // 2) Fallback: берём recent issues + per-issue activities
    let recentIssues = [];
    try {
      const ri = await this.helpers.httpRequest({
        method: 'GET',
        url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/issues/?per_page=' + ISSUES_PER_PROJECT + '&order_by=-updated_at',
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        timeout: 10000, json: true
      });
      recentIssues = Array.isArray(ri) ? ri : (ri.results || []);
    } catch (_) {}

    // Pull activities for each recent issue. Endpoint в Plane v0.27 —
    // /api/v1/workspaces/{slug}/projects/{id}/issues/{issue_id}/activities/
    for (const iss of recentIssues) {
      const issueUrls = [
        planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/issues/' + iss.id + '/activities/?per_page=20',
        planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + p.id + '/issues/' + iss.id + '/history/?per_page=20'
      ];
      for (const u of issueUrls) {
        try {
          const r = await this.helpers.httpRequest({
            method: 'GET', url: u,
            headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
            timeout: 6000, json: true
          });
          const list = Array.isArray(r) ? r : (r.results || []);
          if (list.length) {
            list.forEach(a => {
              a._project = p.name;
              a._issue_name = iss.name;
              a._issue_sequence_id = iss.sequence_id;
              a.issue = a.issue || iss.id;
            });
            activities.push.apply(activities, list);
            break;
          }
        } catch (_) { /* try next */ }
      }
    }

    // 3) Если и activities/history пусты — синтезируем «обновлено N мин назад»
    // из самих recent issues (хоть так будет видно, что задача недавно менялась).
    if (activities.length === 0 && recentIssues.length) {
      recentIssues.slice(0, 15).forEach(iss => {
        activities.push({
          id: 'synth-' + iss.id,
          field: 'updated',
          new_value: iss.name,
          comment: null,
          actor_detail: null,
          actor: 'система',
          issue: iss.id,
          _project: p.name,
          _issue_name: iss.name,
          _issue_sequence_id: iss.sequence_id,
          created_at: iss.updated_at || iss.created_at
        });
      });
    }
  }

  // Фильтр «мои»
  const myOnly = params.scope === 'me' || params.scope === 'mine' || String(params.query || '').toLowerCase().includes('мо');
  let filtered = activities;
  if (myOnly && meId) {
    filtered = activities.filter(a => String(a.actor || a.actor_id || (a.actor_detail && a.actor_detail.id) || '') === String(meId));
  }
  filtered.sort((a,b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));
  filtered = filtered.slice(0, 30);

  const events = filtered.map(a => ({
    id: a.id,
    field: a.field || a.verb || '',
    new_value: a.new_value,
    old_value: a.old_value,
    comment: a.comment,
    actor: (a.actor_detail && (a.actor_detail.display_name || a.actor_detail.email)) || a.actor || '',
    issue_id: a.issue,
    issue_name: a._issue_name,
    issue_sequence_id: a._issue_sequence_id,
    project: a._project,
    created_at: a.created_at
  }));
  return [{ json: {
    response: events.length
      ? ('Событий: ' + events.length + (myOnly ? ' (мои)' : ''))
      : 'Событий не найдено. Активность собирается из последних изменённых задач — если задач нет или они давно не менялись, лента пуста.',
    action: 'list_activity',
    data: { activities: events, my_only: myOnly }
  } }];
}

// === create_epic: создаёт parent-задачу + bulk children с parent_id ===
if (action === 'create_epic') {
  const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  const projName = String(params.project_name || '').toLowerCase();
  const proj = allProjects.find(p => String(p.name).toLowerCase() === projName);
  if (!proj) {
    return [{ json: { response: 'Проект не найден: ' + params.project_name, action: 'create_epic', data: null, error: 'project_not_found' } }];
  }
  const epicName = String(params.epic_name || params.name || '').trim();
  if (!epicName) {
    return [{ json: { response: 'Не указано имя эпика.', action: 'create_epic', data: null, error: 'epic_name_required' } }];
  }
  const children = Array.isArray(params.children) ? params.children : [];
  if (!children.length) {
    return [{ json: { response: 'Не указаны под-задачи эпика.', action: 'create_epic', data: null, error: 'children_required' } }];
  }
  let epicId = null, epicSeq = null;
  try {
    const ep = await this.helpers.httpRequest({
      method: 'POST',
      url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/issues/',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      body: {
        name: epicName,
        description_html: params.description ? '<p>' + String(params.description).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</p>' : '<p></p>',
        priority: ['urgent','high','medium','low','none'].includes(params.priority) ? params.priority : 'medium'
      },
      timeout: 15000, json: true
    });
    epicId = ep.id; epicSeq = ep.sequence_id;
  } catch (e) {
    return [{ json: { response: 'Не удалось создать эпик: ' + (e.message || e), action: 'create_epic', data: null, error: 'epic_create_failed' } }];
  }
  const created = [];
  const failed = [];
  for (const ch of children) {
    const chName = typeof ch === 'string' ? ch : (ch.name || '');
    if (!chName) continue;
    try {
      const chBody = {
        name: chName,
        parent: epicId,
        priority: ['urgent','high','medium','low','none'].includes(ch.priority) ? ch.priority : 'none'
      };
      if (ch.description) chBody.description_html = '<p>' + String(ch.description).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</p>';
      if (ch.target_date && /^\d{4}-\d{2}-\d{2}$/.test(ch.target_date)) chBody.target_date = ch.target_date;
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/issues/',
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        body: chBody, timeout: 15000, json: true
      });
      created.push({ id: r.id, name: r.name, sequence_id: r.sequence_id });
    } catch (e) {
      failed.push({ name: chName, error: String(e.message || e).slice(0, 100) });
    }
  }
  return [{ json: {
    response: 'Эпик «' + epicName + '» создан (#' + epicSeq + '). Под-задач: ' + created.length + (failed.length ? ', ошибок: ' + failed.length : '') + '.',
    action: 'create_epic',
    data: { epic: { id: epicId, name: epicName, sequence_id: epicSeq }, children: created, failed: failed, project_id: proj.id, project_name_canonical: proj.name }
  } }];
}

// === list_comments: GET /api/v1/.../issues/{id}/comments/ ===
if (action === 'list_comments') {
  const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
  const projName = String(params.project_name || '').toLowerCase();
  const proj = allProjects.find(p => String(p.name).toLowerCase() === projName);
  if (!proj) {
    return [{ json: { response: 'Проект не найден: ' + params.project_name, action: 'list_comments', data: null, error: 'project_not_found' } }];
  }
  const issues = await getIssues.call(this, proj.id);
  const issueName = String(params.issue_name || '').toLowerCase();
  const issue = issues.find(i => String(i.name || '').toLowerCase() === issueName);
  if (!issue) {
    return [{ json: { response: 'Задача не найдена: ' + params.issue_name, action: 'list_comments', data: null, error: 'issue_not_found' } }];
  }
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/issues/' + issue.id + '/comments/?expand=actor_detail',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 15000, json: true
    });
    const comments = Array.isArray(r) ? r : (r.results || []);
    return [{ json: {
      response: 'Комментариев: ' + comments.length,
      action: 'list_comments',
      data: { comments: comments, issue_id: issue.id, issue_name: issue.name }
    } }];
  } catch (e) {
    return [{ json: { response: 'Не удалось загрузить комментарии: ' + (e.message || e), action: 'list_comments', data: null, error: 'comments_fetch_failed' } }];
  }
}

const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
const scope = params.scope || 'summary';
const requestedProject = params.project_name;
const filterProjects = requestedProject
  ? allProjects.filter(p => String(p.name).toLowerCase() === String(requestedProject).toLowerCase())
  : allProjects;

let response = '';
let issuesAll = [];
for (const p of filterProjects) {
  const issues = await getIssues.call(this, p.id);
  issues.forEach(i => { i._project_name = p.name; });
  issuesAll = issuesAll.concat(issues);
}

const today = new Date(); today.setHours(0,0,0,0);

if (action === 'stats') {
  if (scope === 'overdue') {
    const overdue = issuesAll.filter(i => i.target_date && new Date(i.target_date) < today
      && (i.state_detail && i.state_detail.group !== 'completed' && i.state_detail.group !== 'cancelled'));
    if (!overdue.length) {
      response = 'Просроченных задач нет.';
    } else {
      const lines = overdue.slice(0, 20).map(i => '• ' + i.name + ' (срок: ' + i.target_date + ', проект: ' + i._project_name + ')');
      response = 'Просрочено: ' + overdue.length + ' задач.' + NL + lines.join(NL) +
        (overdue.length > 20 ? NL + '...и ещё ' + (overdue.length - 20) : '');
    }
  } else if (scope === 'summary') {
    const total = issuesAll.length;
    const byGroup = {unstarted:0,started:0,completed:0,cancelled:0,backlog:0};
    issuesAll.forEach(i => {
      const g = (i.state_detail && i.state_detail.group) || 'unstarted';
      byGroup[g] = (byGroup[g] || 0) + 1;
    });
    response = (filterProjects.length === 1 ? 'Проект «' + filterProjects[0].name + '»: ' : 'По всем проектам: ') +
      'всего ' + total + ' задач.' + NL +
      'Задачи: ' + (byGroup.unstarted + byGroup.backlog) + NL +
      'В работе: ' + byGroup.started + NL +
      'Готово: ' + byGroup.completed + NL +
      'Отменено: ' + byGroup.cancelled;
  } else if (scope === 'by_assignee') {
    const q = String(params.assignee_query || '').toLowerCase().trim();
    const filtered = q ? issuesAll.filter(i => Array.isArray(i.assignees) && i.assignees.length > 0) : issuesAll;
    const byAssignee = {};
    filtered.forEach(i => {
      (i.assignees || []).forEach(uid => {
        byAssignee[uid] = (byAssignee[uid] || 0) + 1;
      });
    });
    const top = Object.entries(byAssignee).sort((a,b) => b[1]-a[1]).slice(0, 15);
    if (!top.length) {
      response = 'Не нашёл задач с назначенными исполнителями.';
    } else {
      response = (q ? 'Запрос про «' + params.assignee_query + '». ' : '') +
        'Статистика по исполнителям (топ-' + top.length + '):' + NL +
        top.map(([uid, cnt]) => '• ' + uid.slice(0,8) + '... — ' + cnt + ' задач').join(NL) +
        NL + '(имена доступны только через детальный API запрос — уточни в задаче по issue_id).';
    }
  } else if (scope === 'my_workload') {
    const opened = issuesAll.filter(i => i.state_detail && (i.state_detail.group === 'unstarted' || i.state_detail.group === 'started' || i.state_detail.group === 'backlog'));
    response = 'Открытых задач (в работе и в очереди): ' + opened.length + '.' + NL +
      (opened.length > 0 ? 'Первые 10:' + NL +
        opened.slice(0,10).map(i => '• ' + i.name + ' (' + i._project_name + ')').join(NL) : '');
  } else {
    response = 'Неизвестный scope для stats: ' + scope;
  }
} else if (action === 'cross_project_search') {
  const q = String(params.query || '').toLowerCase().trim();
  const filter = params.filter || '';
  let result = issuesAll;
  if (q) result = result.filter(i => String(i.name || '').toLowerCase().includes(q));
  if (filter === 'overdue') {
    result = result.filter(i => i.target_date && new Date(i.target_date) < today);
  } else if (filter === 'urgent') {
    result = result.filter(i => String(i.priority || '').toLowerCase() === 'urgent');
  }
  if (!result.length) {
    response = 'По запросу «' + (q || '(все)') + '»' + (filter ? ' с фильтром ' + filter : '') + ' ничего не нашлось.';
  } else {
    const lines = result.slice(0, 20).map(i => '• ' + i.name + ' (' + i._project_name + (i.target_date ? ', срок ' + i.target_date : '') + ')');
    response = 'Найдено по всем проектам: ' + result.length + ' задач.' + NL + lines.join(NL) +
      (result.length > 20 ? NL + '...и ещё ' + (result.length - 20) : '');
  }
}

// BUG-FIX #4: если статистика вернула пустой результат ('Просрочек нет',
// 'Задач не найдено'), НЕ подкладываем issues — иначе фронт рендерит
// все 50 задач хотя ответ говорит «нет».
const responseLow = String(response||'').toLowerCase();
const isEmptyResult = /\b(нет|не найден|не нашёл|не нашел|ничего|пуст)\b/.test(responseLow);
// BUG-FIX #5: использовать ФИЛЬТРОВАННЫЙ result для cross_project_search.
// Раньше выкладывали ВСЕ задачи (issuesAll) даже когда ответ говорил «нашёл 2 срочные».
let sourceForData = issuesAll;
try { if (typeof result !== 'undefined' && Array.isArray(result)) sourceForData = result; } catch(_) {}
const dataIssues = isEmptyResult ? null : sourceForData.slice(0, 50).map(i => ({ id: i.id, name: i.name, sequence_id: i.sequence_id, priority: i.priority, target_date: i.target_date, start_date: i.start_date, project: i._project_name, state_detail: i.state_detail }));
return [{ json: {
  response: response || 'Готово.',
  action: action,
  data: dataIssues ? { issues: dataIssues } : null
} }];
